/* Couleurs : hex, rgb, ou noms */
.texte-principal {
  color: #111827;             /* gris très foncé */
  background-color: #f9fafb;  /* gris très clair */
}

/* Couleurs avec transparence (rgba) */
.overlay {
  background-color: rgba(0, 0, 0, 0.5); /* noir à 50% d'opacité */
}

/* Typographie */
body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  font-size: 16px;       /* taille de base */
  line-height: 1.6;      /* interligne (1.5-1.7 est confortable à lire) */
  color: #374151;
}

h1 {
  font-size: 2.25rem;    /* rem = relatif à la taille de base */
  font-weight: 700;      /* graisse : 400 normal, 700 bold */
  letter-spacing: -0.02em; /* espacement des lettres */
}
